#define DEFAULT_COUNT 6
#define FIXED_CLAMP(X,L,H) \
        MAX((L), MIN((H), (X)))
#define TRACE_TEXT 'trace disabled'
C STRESS FIXTURE FOR CLASSIC COLUMNS AND MODERN FORTRAN TOKENS.
c LOWERCASE C IN COLUMN ONE STARTS A COMMENT TOO.
* UNICODE COMMENT: CAFÉ, λ-CALCULUS, 雪, AND ASTRAL 🛰️🚀.
      ! AN EXCLAMATION COMMENT MAY FOLLOW THE FIXED-FORM MARGIN.
      MODULE FIXED_SUPPORT
      USE, INTRINSIC :: ISO_FORTRAN_ENV, ONLY: REAL64, INT32,
     1       ERROR_UNIT
      IMPLICIT NONE
      PRIVATE
      PUBLIC :: SAMPLE_T, CLAMP_VALUE, FILL_SAMPLE, DESCRIBE_ITEM
      PUBLIC :: DESCRIBE_RANK, TRANSFORM_FN
      REAL(REAL64), PARAMETER :: EPSILON = 1.0E-10_REAL64
      ABSTRACT INTERFACE
      PURE FUNCTION TRANSFORM_FN(X) RESULT(Y)
      IMPORT :: REAL64
      REAL(REAL64), INTENT(IN) :: X
      REAL(REAL64) Y
      END FUNCTION TRANSFORM_FN
      END INTERFACE
      INTERFACE CLAMP_VALUE
      MODULE PROCEDURE CLAMP_REAL
      END INTERFACE CLAMP_VALUE
      TYPE, PUBLIC :: SAMPLE_T
      INTEGER(INT32) :: ID = 0_INT32
      CHARACTER(LEN=:), ALLOCATABLE :: LABEL
      REAL(REAL64), ALLOCATABLE :: VALUES(:)
      CONTAINS
      PROCEDURE, PUBLIC :: MEAN => SAMPLE_MEAN
      PROCEDURE, PUBLIC :: SCALE => SAMPLE_SCALE
      FINAL :: FINALIZE_SAMPLE
      END TYPE SAMPLE_T
      CONTAINS
      PURE FUNCTION SAMPLE_MEAN(SELF) RESULT(ANSWER)
      CLASS(SAMPLE_T), INTENT(IN) :: SELF
      REAL(REAL64) ANSWER
      IF (ALLOCATED(SELF%VALUES) .AND.
     1    SIZE(SELF%VALUES) .GT. 0) THEN
      ANSWER = SUM(SELF%VALUES) /
     2         REAL(SIZE(SELF%VALUES), REAL64)
      ELSE
      ANSWER = 0.0_REAL64
      END IF
      END FUNCTION SAMPLE_MEAN
      SUBROUTINE SAMPLE_SCALE(SELF, FACTOR)
      CLASS(SAMPLE_T), INTENT(INOUT) :: SELF
      REAL(REAL64), INTENT(IN), VALUE :: FACTOR
      IF (.NOT. ALLOCATED(SELF%VALUES)) RETURN
      WHERE (SELF%VALUES .GE. 0.0_REAL64)
      SELF%VALUES = SELF%VALUES * FACTOR
      ELSEWHERE
      SELF%VALUES = -ABS(SELF%VALUES) * FACTOR
      END WHERE
      END SUBROUTINE SAMPLE_SCALE
      SUBROUTINE FINALIZE_SAMPLE(SELF)
      TYPE(SAMPLE_T), INTENT(INOUT) :: SELF
      IF (ALLOCATED(SELF%VALUES)) DEALLOCATE(SELF%VALUES)
      IF (ALLOCATED(SELF%LABEL)) DEALLOCATE(SELF%LABEL)
      END SUBROUTINE FINALIZE_SAMPLE
      ELEMENTAL REAL(REAL64) FUNCTION CLAMP_REAL(VALUE, LOWER,
     1       UPPER)
      REAL(REAL64), INTENT(IN) :: VALUE, LOWER, UPPER
      CLAMP_REAL = MAX(LOWER, MIN(UPPER, VALUE))
      END FUNCTION CLAMP_REAL
      SUBROUTINE FILL_SAMPLE(ITEM, OPERATION)
      TYPE(SAMPLE_T), INTENT(INOUT) :: ITEM
      PROCEDURE(TRANSFORM_FN) :: OPERATION
      INTEGER I
      DO CONCURRENT (I = 1:SIZE(ITEM%VALUES))
      ITEM%VALUES(I) = OPERATION(ITEM%VALUES(I))
      END DO
      END SUBROUTINE FILL_SAMPLE
      SUBROUTINE DESCRIBE_ITEM(ITEM)
      CLASS(*), INTENT(IN) :: ITEM
      SELECT TYPE (ITEM)
      TYPE IS (INTEGER)
      WRITE (*,'(A,I0)') 'INTEGER=', ITEM
      TYPE IS (SAMPLE_T)
      WRITE (*,'(A,A)') 'SAMPLE=', ITEM%LABEL
      CLASS DEFAULT
      WRITE (ERROR_UNIT,'(A)') 'UNKNOWN DYNAMIC TYPE'
      END SELECT
      END SUBROUTINE DESCRIBE_ITEM
      SUBROUTINE DESCRIBE_RANK(DATA)
      REAL(REAL64), INTENT(IN) :: DATA(..)
      SELECT RANK (VIEW => DATA)
      RANK (0)
      WRITE (*,'(A,F7.3)') 'SCALAR ', VIEW
      RANK (1)
      WRITE (*,'(A,I0)') 'VECTOR SIZE ', SIZE(VIEW)
      RANK DEFAULT
      WRITE (*,'(A,I0)') 'OTHER RANK ', RANK(VIEW)
      END SELECT
      END SUBROUTINE DESCRIBE_RANK
      END MODULE FIXED_SUPPORT
      BLOCK DATA LEGACY_DEFAULTS
      IMPLICIT NONE
      REAL COMMON_VALUE
      INTEGER COMMON_FLAG
      COMMON /LEGACY_STATE/ COMMON_VALUE, COMMON_FLAG
      DATA COMMON_VALUE, COMMON_FLAG /2.5, 1/
      END BLOCK DATA LEGACY_DEFAULTS
      PROGRAM STRESS_FIXED
      USE, INTRINSIC :: ISO_FORTRAN_ENV, ONLY: REAL64, INT32
      USE FIXED_SUPPORT, ONLY: SAMPLE_T, CLAMP_VALUE,
     1       FILL_SAMPLE, DESCRIBE_ITEM, DESCRIBE_RANK
      IMPLICIT NONE
      TYPE(SAMPLE_T) LEFT, RIGHT
      REAL(REAL64), ALLOCATABLE :: WORK(:)
      REAL(REAL64), TARGET :: TARGET_VALUE
      REAL(REAL64), POINTER :: POINTER_VALUE
      REAL(REAL64) GRID(2,3), TOTAL
      REAL SCRATCH(6), ALIAS(6)
      REAL COMMON_VALUE, LEGACY_STEP
      INTEGER COMMON_FLAG
      INTEGER I, J, PHASE, UNIT, STATUS, TICK
      INTEGER(INT32) :: CODE
      CHARACTER*160 MESSAGE
      CHARACTER*32 RECORD
      LOGICAL EXISTS, ACTIVE
      COMMON /LEGACY_STATE/ COMMON_VALUE, COMMON_FLAG
      EQUIVALENCE (SCRATCH(1), ALIAS(1))
      NAMELIST /CONTROL/ PHASE, ACTIVE, MESSAGE
      EXTERNAL LEGACY_STEP
      INTRINSIC SQRT
      SAVE TICK
      DATA TICK /0/
      DATA GRID /1.0_REAL64, 2.0_REAL64, 3.0_REAL64,
     1           4.0_REAL64, 5.0_REAL64, 6.0_REAL64/
C THE OPEN QUOTE CONTINUES THROUGH COLUMN-SIX CONTINUATION LINES.
      MESSAGE = 'Unicode λ雪 and astral 🚀 remain inside one long
     1 character literal, with an apostrophe''s escape and more
     + text on a third physical line.'
      ACTIVE = .TRUE.
      PHASE = DEFAULT_COUNT / 2
      CODE = INT(Z'2A', INT32)
      LEFT%ID = 1_INT32
      LEFT%LABEL = 'LEFT'
      ALLOCATE(LEFT%VALUES(4), SOURCE=0.0_REAL64, STAT=STATUS)
      IF (STATUS .NE. 0) ERROR STOP 'LEFT ALLOCATION FAILED'
      LEFT%VALUES = [1.0_REAL64, -2.0_REAL64,
     1               3.5_REAL64, 5.0_REAL64]
      RIGHT = SAMPLE_T(ID=2_INT32, LABEL='RIGHT',
     2         VALUES=(/0.5_REAL64, 2.0_REAL64,
     3                  4.5_REAL64, 8.0_REAL64/))
      CALL LEFT%SCALE(2.0_REAL64)
      CALL FILL_SAMPLE(LEFT, SQUARE_VALUE)
      CALL DESCRIBE_ITEM(LEFT)
      CALL DESCRIBE_RANK(LEFT%VALUES)
      ALLOCATE(WORK(DEFAULT_COUNT), SOURCE=0.0_REAL64,
     &         STAT=STATUS)
      IF (STATUS /= 0) STOP 2
      CALL RANDOM_NUMBER(WORK)
      WORK = CLAMP_VALUE(WORK, 0.2_REAL64, 0.8_REAL64)
      TARGET_VALUE = 2.0_REAL64
      POINTER_VALUE => TARGET_VALUE
      POINTER_VALUE = POINTER_VALUE ** 3
      NULLIFY(POINTER_VALUE)
      ASSOCIATE (AVERAGE => LEFT%MEAN(),
     1           COUNT => SIZE(LEFT%VALUES))
      WRITE (*,100) COUNT, AVERAGE, MESSAGE
      END ASSOCIATE
  100 FORMAT (1X,'COUNT=',I3,2X,'MEAN=',F8.3,
     1        /,1X,'MESSAGE: ',A,
     2        /,1X,'END OF MULTILINE FORMAT')
      BLOCK
      REAL(REAL64) NORMALIZED(SIZE(RIGHT%VALUES))
      NORMALIZED = RIGHT%VALUES /
     $ MAX(1.0_REAL64, MAXVAL(ABS(RIGHT%VALUES)))
      RIGHT%VALUES = MERGE(NORMALIZED, 0.0_REAL64,
     1                     ABS(NORMALIZED) .GT. 1.0E-10_REAL64)
      END BLOCK
      TOTAL = 0.0_REAL64
      OUTER: DO I = 1, SIZE(RIGHT%VALUES)
      IF (RIGHT%VALUES(I) .LT. 0.0_REAL64) CYCLE OUTER
      SELECT CASE (I)
      CASE (1)
      RIGHT%VALUES(I) = RIGHT%VALUES(I) + 1.0_REAL64
      CASE (2:3)
      RIGHT%VALUES(I) = RIGHT%VALUES(I) / 2.0_REAL64
      CASE DEFAULT
      EXIT OUTER
      END SELECT
      TOTAL = TOTAL + RIGHT%VALUES(I)
      END DO OUTER
      WHERE (GRID .GT. 3.0_REAL64)
      GRID = GRID - 1.0_REAL64
      ELSEWHERE (GRID .EQ. 3.0_REAL64)
      GRID = 0.0_REAL64
      ELSEWHERE
      GRID = GRID + 1.0_REAL64
      END WHERE
      FORALL (I=1:2, J=1:3, I+J .GT. 2)
      GRID(I,J) = GRID(I,J) + REAL(I*J, REAL64)
      END FORALL
      DO 210 I = 1, 3
      SCRATCH(I) = LEGACY_STEP(REAL(I))
  210 CONTINUE
      GO TO (310, 320, 330), PHASE
  310 TOTAL = TOTAL - 1.0_REAL64
      GO TO 340
  320 TOTAL = TOTAL + 0.0_REAL64
      GO TO 340
  330 TOTAL = TOTAL + 1.0_REAL64
  340 CONTINUE
      IF (TOTAL) 350, 360, 370
  350 STATUS = -1
      GO TO 380
  360 STATUS = 0
      GO TO 380
  370 STATUS = 1
  380 CONTINUE
      INQUIRE (FILE='fixed_fixture.dat', EXIST=EXISTS)
      OPEN (NEWUNIT=UNIT, FILE='fixed_fixture.dat', STATUS='REPLACE',
     1      ACTION='READWRITE', IOSTAT=STATUS)
      IF (STATUS .EQ. 0) THEN
      WRITE (UNIT,400,IOSTAT=STATUS) CODE, TOTAL, TRACE_TEXT
      REWIND (UNIT,IOSTAT=STATUS)
      READ (UNIT,'(A)',IOSTAT=STATUS) RECORD
      FLUSH (UNIT)
      CLOSE (UNIT,STATUS='DELETE',IOSTAT=STATUS)
      END IF
  400 FORMAT (1X,'CODE=',I4,1X,'TOTAL=',ES12.4,
     1        1X,'TRACE=',A)
      TICK = TICK + 1
      DO WHILE (TICK .LT. 2)
      TICK = TICK + 1
      END DO
	CALL DESCRIBE_ITEM(STATUS)
      WRITE (*,500) 'DONE', STATUS
  500 FORMAT (1X,A,':',SP,I4,SS,2X,L1)
      IF (ALLOCATED(WORK)) DEALLOCATE(WORK)
      IF (ALLOCATED(RIGHT%VALUES)) DEALLOCATE(RIGHT%VALUES)
      STOP 'NORMAL END'
      CONTAINS
      PURE FUNCTION SQUARE_VALUE(X) RESULT(Y)
      REAL(REAL64), INTENT(IN) :: X
      REAL(REAL64) Y
      Y = X * X
      END FUNCTION SQUARE_VALUE
      END PROGRAM STRESS_FIXED
      REAL FUNCTION LEGACY_STEP(X)
      IMPLICIT NONE
      REAL X
      LEGACY_STEP = SQRT(ABS(X)) + 1.0
      RETURN
      END FUNCTION LEGACY_STEP
